head.script:
/**
 * 화 면 명 : 선급비용대사
 * 메뉴경로 : 회계/재무회계/일반회계/선급비용관리/
 * ASIS경로 : /dongwon-debis-engine/src/main/webapp/ac/fi/gnrlaccount/prepaycostmgnt/fi_202_03_01b.jsp
 * 작 성 자 : 정승혜
 * 작 업 일 : 2025-12-16
 * 수정이력  :
 *    - 2025-12-16      정승혜    최초작성
 *    - 2026-01-22      정승혜    기타수정
 * 메모 : asis는 소계포함 total수 , tobe 는 소계빼고 total수  / 엑셀다운하여 데이터 확인완료
 * 조회조건 : 201001/201101
 */
scwin.memJson = $c.data.getMemInfo();

scwin.privAdmin = $c.data.getMemInfo("privAdmin");    // ADMIN 권한 CHK : 'T' : ADMIN , 'F': ADMIN 아님
scwin.empNo = scwin.memJson.userId;           //사용자 아이디

scwin.valueObject = "";

scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd; // 소속 자회사  
scwin.vLoginCoClsCd = $c.gus.cfIsNull(scwin.memJson.coClsCd) ? '' : scwin.memJson.coClsCd;//회계_회사구분('CO035' : 0:동부 EXPRESS)
scwin.vUserHomeClsCd= scwin.memJson.userHomeClsCd;  // 사용자소속구분코드 
scwin.g_sLoginDept = scwin.memJson.acctDeptCd;
scwin.isSubCompany = false;
scwin.coCd = "000";
scwin.coClsCd = "0";

scwin.dDate = $c.date.getServerDateTime("yyyyMMdd");

//hidden
scwin.txtCoClsCd = "";

	//-------------------------------------------------------------------------
	// 화면로딩시
	//-------------------------------------------------------------------------
scwin.onpageload = function() {

};

// UDC값 초기화(scwin.onpageload 이후 세팅됨)
scwin.onUdcCompleted = function() {
    scwin.f_Header();
    ed_closeYm.setValue(scwin.dDate);
    ed_closeYm.focus();
    scwin.f_setCompanyInfo(); //자회사여부  

    $c.gus.cfDisableObjects([ed_coCd,ed_coNm]);	
};

	//-------------------------------------------------------------------------
	// 헤더생성
	//-------------------------------------------------------------------------
scwin.f_Header = function() {
    // DataSet의 Header 정보 생성(TODO:TOBE 데이터맵으로 셋팅하므로 필요없음)
};

	//-------------------------------------------------------------------------
	// 자회사 회계 시스템 추가에 따른 설정 
	//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function() {
    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
    if (scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
    }
    ed_coCd.setValue(scwin.vLoginCoCd);
    dma_search.set("coCd",scwin.vLoginCoCd );
    scwin.f_PopUpCompanyInfo('T');
};

	//-------------------------------------------------------------------------
	// 회사 입력 팝업 
	//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = async function (pWinCloseTF) {
    let rtnList = await udc_companyInfo.cfCommonPopUp(scwin.udc_companyInfo_callBackFunc
                                ,ed_coCd.getValue(), ed_coNm.getValue(),pWinCloseTF,null,null,null,null,null,null,null,null,null

    );
};

scwin.udc_companyInfo_callBackFunc = function(rtnList) {
    if (rtnList != null && rtnList[0] != "N/A") {
        ed_coCd.setValue(rtnList[0]);
        ed_coNm.setValue(rtnList[5]);
        scwin.txtCoClsCd = rtnList[1];
        scwin.coCd = ed_coCd.getValue();
        scwin.coClsCd = rtnList[1];
    } else {
        ed_coCd.setValue("");
        ed_coNm.setValue("");
        scwin.txtCoClsCd = "";
        scwin.coCd = "";
        scwin.coClsCd = "";
    }

    if (scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {  // 자회사 회계 시스템 
        scwin.isSubCompany = true;
    } else {
        scwin.isSubCompany = false;
    }
}

scwin.udc_companyInfo_onclickEvent = function (e) {
    scwin.f_PopUpCompanyInfo('F');
};

	//-------------------------------------------------------------------------
	// function name : f_OpenCommonPopUp
	// function desc : 귀속부서팝업
	//-------------------------------------------------------------------------
scwin.f_OpenCommonPopUp = async function(gubun, pCode, pName, pClose, pAllSearch, row) {
    // 선언부
    let pSelectID 		= "";
    let pWtitleSearch 	= null;
    let param = ","+ed_coCd.getValue()+",,0";  

    let rtnList = await udc_acctDeptCdInfo6.cfCommonPopUp(scwin.udc_acctDeptCdInfo6_callBackFunc
                            ,pCode					// 화면에서의 ??? Code Element의	Value
                            ,pName					// 화면에서의 ??? Name Element의	Value
                            ,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                            ,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                            ,null					// Title순서	
                            ,null					// 보여주는 각 컬럼들의 폭	
                            ,null					// 컬럼중에서 숨기는	컬럼 지정	
                            ,param					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                            ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                            ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                            ,null					// 윈도우 위치 Y좌표	
                            ,null					// 윈도우 위치 X좌표
                            ,null					// 중복체크여부	("F")
                            ,pAllSearch				// 전체검색허용여부	("F")
                            ,pWtitleSearch			// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                            );

}

scwin.udc_acctDeptCdInfo6_callBackFunc = function(rtnList) {
    if (rtnList != null && rtnList[0] != "N/A") {
        ed_deptCd.setValue(rtnList[0]);
        ed_deptNm.setValue(rtnList[1]);
    } else {
        ed_deptCd.setValue("");
        ed_deptNm.setValue("");
    }
}

// onClick="f_OpenCommonPopUp(4, ed_deptCd.Text, txt_deptNm.value, 'F', 'F')"
scwin.udc_acctDeptCdInfo6_onclickEvent = function (e) {
    scwin.f_OpenCommonPopUp(4, ed_deptCd.getValue(), ed_deptNm.getValue(), 'F', 'F');
};

// onChange="f_ChkOpenCommonPopUp(4, this, ed_deptCd, false)">
scwin.udc_acctDeptCdInfo6_onviewchangeNameEvent = function (info) {
    scwin.f_OpenCommonPopUp(4, ed_deptCd.getValue(), ed_deptNm.getValue(), 'T', 'T');
};

// 귀속부서
// f_PopUpCompanyInfo('T');
scwin.udc_acctDeptCdInfo6_onblurCodeEvent = function (e) {
    scwin.f_OpenCommonPopUp(4, ed_deptCd.getValue(), ed_deptNm.getValue(), 'T', 'T');
};

scwin.f_ChkOpenCommonPopUp = function(gubun, inObj, pairObj, isCode) {
    //값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if(!$c.gus.cfCanOpenPopup(inObj, pairObj))	return;

    //짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    //검색어 세팅
    let pVal = $c.gus.cfGetValue(inObj);

    //inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true){
        scwin.f_OpenCommonPopUp(gubun, pVal, '', 'T', 'T');	   
    }else{ //inObj가 코드명 필드일 경우 팝업
        scwin.f_OpenCommonPopUp(gubun, '', pVal, 'T', 'T');
    }
};

	//-------------------------------------------------------------------------
	// 조회
	//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    let ret = await $c.gus.cfValidate([ed_closeYm]);
    if (!ret){
        return false;
    }

    $c.sbm.execute(sbm_tr_search);
    $c.sbm.execute(sbm_tr_search2);
};

	//-------------------------------------------------------------------------
	// 엑셀 파일 다운로드
	//-------------------------------------------------------------------------
// 엑셀다운 1+8+16
scwin.f_Excel = async function() {
    let confirm = await $c.win.confirm("Excel로 다운로드 하시겠습니까?")
    if( confirm ) { 
        const options = {
            fileName : "선급비용대사.xlsx", 
            sheetName : "선급비용대사",
            type : 1,
            useSubTotal:true,
            colMerge : true,
            colMergeTextAlign : "top"
        };
    await $c.data.downloadGridViewExcel(gr_prepayCost, options);
    }  
};

	//-------------------------------------------------------------------------
	// 엑셀 파일 다운로드
	//-------------------------------------------------------------------------
// 엑셀다운 1+8+16
scwin.f_Excel2 = async function() {
    let confirm = await $c.win.confirm("Excel로 다운로드 하시겠습니까?")
    if( confirm ) {
        const options = {
            fileName : "선급비용미등록전표.xlsx", 
            sheetName : "선급비용미등록전표",
            type : 1,
            colMerge : true,
            colMergeTextAlign : "top"
        };
    await $c.data.downloadGridViewExcel(gr_prepayCost2, options);
    }  

};

// 서브미션
scwin.sbm_tr_search_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    totalRows.setValue(ds_prepayCost.getRowCount());
    if(ds_prepayCost.getRowCount() == 0){
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }else{
        ds_prepayCost.sort("acctDeptCd",0);
        ds_prepayCost.setRowPosition(0);
        $c.gus.cfGoPrevPosition(gr_prepayCost, 0);
    }
};

// 서브미션
scwin.sbm_tr_search2_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    totalRows2.setValue(ds_prepayCost2.getRowCount());
    if(ds_prepayCost2.getRowCount() == 0){
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }else{
        ds_prepayCost2.setRowPosition(0);
        $c.gus.cfGoPrevPosition(gr_prepayCost2, 0);
    } 
};

scwin.gr_prepayCost2_oncellclick = function (rowIndex, columnIndex, columnId) {
    if(columnId=="slipNo"){
		$c.gus.cfShowSlipInfo(ds_prepayCost2.getCellData(rowIndex,"slipNo"));
	}
};

// 회사코드
scwin.udc_companyInfo_onblurCodeEvent = function (e) {
    ed_coNm.setValue('');
	scwin.f_PopUpCompanyInfo('T');
	ed_deptCd.setValue("");
	ed_deptNm.setValue("");
};
